namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string PhotoUrl { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public int InstructorId { get; set; }
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
    public int MaxEnrollment { get; set; }
    public int CurrentEnrollment { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language arts." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and civilizations." },
            new() { Id = 6, Code = "BIOL", Name = "Biology", Description = "Study of living organisms and their interactions." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Email = "achen@university.edu", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 research papers and holds three patents in neural network architectures.", PhotoUrl = "" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor", Email = "rmartinez@university.edu", Bio = "Dr. Martinez focuses on abstract algebra and number theory. He received the Distinguished Teaching Award in 2023.", PhotoUrl = "" },
            new() { Id = 3, Name = "Dr. Sarah Johnson", Title = "Professor", Email = "sjohnson@university.edu", Bio = "Dr. Johnson is a leading researcher in quantum mechanics with over 20 years of experience in experimental physics.", PhotoUrl = "" },
            new() { Id = 4, Name = "Prof. James Wilson", Title = "Assistant Professor", Email = "jwilson@university.edu", Bio = "Prof. Wilson is a published author and literary critic specializing in 20th-century American literature.", PhotoUrl = "" },
            new() { Id = 5, Name = "Dr. Emily Davis", Title = "Professor", Email = "edavis@university.edu", Bio = "Dr. Davis is a historian specializing in medieval European history and has led several archaeological expeditions.", PhotoUrl = "" },
            new() { Id = 6, Name = "Dr. Michael Brown", Title = "Associate Professor", Email = "mbrown@university.edu", Bio = "Dr. Brown researches molecular genetics and has contributed to breakthroughs in gene therapy treatments.", PhotoUrl = "" },
            new() { Id = 7, Name = "Dr. Lisa Park", Title = "Assistant Professor", Email = "lpark@university.edu", Bio = "Dr. Park specializes in distributed systems and cloud computing. She previously worked at a major tech company for 8 years.", PhotoUrl = "" },
            new() { Id = 8, Name = "Dr. David Kim", Title = "Professor", Email = "dkim@university.edu", Bio = "Dr. Kim is an expert in statistical analysis and applied probability with extensive industry consulting experience.", PhotoUrl = "" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "An introductory course covering fundamental concepts of computer science including algorithms, data structures, and programming basics using Python.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 120, CurrentEnrollment = 98 },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures and Algorithms", Description = "Advanced study of data structures (trees, graphs, hash tables) and algorithm design techniques including dynamic programming and greedy algorithms.", Credits = 4, Schedule = "Tue/Thu 10:00–11:15 AM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 7, IsFeatured = false, MaxEnrollment = 60, CurrentEnrollment = 55 },
            new() { Id = 3, Code = "CS 450", Title = "Artificial Intelligence", Description = "Explores the principles and techniques of AI including search, knowledge representation, machine learning, and natural language processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Location = "Tech Building 110", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 45, CurrentEnrollment = 42 },
            new() { Id = 4, Code = "MATH 201", Title = "Calculus I", Description = "Covers limits, derivatives, and integrals of single-variable functions with applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 101", DepartmentId = 2, InstructorId = 2, IsFeatured = false, MaxEnrollment = 150, CurrentEnrollment = 130 },
            new() { Id = 5, Code = "MATH 305", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, and eigenvalues with applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", Location = "Math Building 203", DepartmentId = 2, InstructorId = 8, IsFeatured = true, MaxEnrollment = 60, CurrentEnrollment = 48 },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Introduction to classical mechanics, thermodynamics, and waves. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM + Lab Fri 1:00–3:50 PM", Location = "Physics Lab 100", DepartmentId = 3, InstructorId = 3, IsFeatured = false, MaxEnrollment = 80, CurrentEnrollment = 72 },
            new() { Id = 7, Code = "PHYS 410", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave functions, the Schrödinger equation, and quantum entanglement.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Physics Lab 302", DepartmentId = 3, InstructorId = 3, IsFeatured = true, MaxEnrollment = 30, CurrentEnrollment = 25 },
            new() { Id = 8, Code = "ENG 110", Title = "College Writing", Description = "Develops critical reading, thinking, and writing skills through analysis of diverse texts and composition practice.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Humanities 105", DepartmentId = 4, InstructorId = 4, IsFeatured = false, MaxEnrollment = 25, CurrentEnrollment = 24 },
            new() { Id = 9, Code = "ENG 350", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present, exploring themes of identity and society.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", Location = "Humanities 210", DepartmentId = 4, InstructorId = 4, IsFeatured = false, MaxEnrollment = 35, CurrentEnrollment = 28 },
            new() { Id = 10, Code = "HIST 101", Title = "World History I", Description = "Survey of world civilizations from ancient times through the Renaissance, covering major cultural, political, and economic developments.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", Location = "Humanities 301", DepartmentId = 5, InstructorId = 5, IsFeatured = false, MaxEnrollment = 100, CurrentEnrollment = 85 },
            new() { Id = 11, Code = "HIST 320", Title = "Medieval Europe", Description = "In-depth study of European history from the fall of Rome to the Renaissance, including feudalism, the Crusades, and the Black Death.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", Location = "Humanities 305", DepartmentId = 5, InstructorId = 5, IsFeatured = true, MaxEnrollment = 40, CurrentEnrollment = 33 },
            new() { Id = 12, Code = "BIOL 101", Title = "General Biology", Description = "Introduction to biological principles including cell biology, genetics, evolution, and ecology. Includes laboratory work.", Credits = 4, Schedule = "Mon/Wed 9:00–10:15 AM + Lab Thu 2:00–4:50 PM", Location = "Life Sciences 100", DepartmentId = 6, InstructorId = 6, IsFeatured = false, MaxEnrollment = 90, CurrentEnrollment = 78 },
            new() { Id = 13, Code = "BIOL 420", Title = "Molecular Genetics", Description = "Advanced study of gene structure, expression, and regulation at the molecular level, including modern genetic engineering techniques.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", Location = "Life Sciences 310", DepartmentId = 6, InstructorId = 6, IsFeatured = true, MaxEnrollment = 35, CurrentEnrollment = 30 },
            new() { Id = 14, Code = "MATH 410", Title = "Probability and Statistics", Description = "Comprehensive introduction to probability theory, random variables, distributions, and statistical inference methods.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", Location = "Math Building 105", DepartmentId = 2, InstructorId = 8, IsFeatured = false, MaxEnrollment = 50, CurrentEnrollment = 41 },
            new() { Id = 15, Code = "CS 480", Title = "Distributed Systems", Description = "Principles of distributed computing including consensus algorithms, replication, fault tolerance, and cloud architectures.", Credits = 3, Schedule = "Tue/Thu 4:00–5:15 PM", Location = "Tech Building 205", DepartmentId = 1, InstructorId = 7, IsFeatured = false, MaxEnrollment = 40, CurrentEnrollment = 35 },
        };

        // Wire up navigation properties
        foreach (var course in _courses)
        {
            course.Department = _departments.First(d => d.Id == course.DepartmentId);
            course.Instructor = _instructors.First(i => i.Id == course.InstructorId);
        }
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollmentRequests.Add(request);
    }
}

