@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the Fall 2026 semester course catalog. Browse departments, explore courses, and submit your enrollment request.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                    <span class="badge bg-primary me-1">@course.Credits Credits</span>
                    <span class="badge bg-secondary">@course.Department.Name</span>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text text-muted">@dept.Description</p>
                    <a href="courses?department=@dept.Id" class="btn btn-sm btn-outline-secondary">
                        Browse @dept.Code Courses →
                    </a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor…"
               @bind="searchTerm" @bind:event="oninput" @bind:after="ApplyFilters" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId" @bind:after="ApplyFilters">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name (@dept.Code)</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

<p class="text-muted">Showing @filteredCourses.Count course(s)</p>

<table class="table table-striped table-hover">
    <thead>
        <tr>
            <th>Code</th>
            <th>Title</th>
            <th>Department</th>
            <th>Credits</th>
            <th>Instructor</th>
            <th>Schedule</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var course in filteredCourses)
        {
            <tr>
                <td><strong>@course.Code</strong></td>
                <td>@course.Title</td>
                <td>@course.Department.Name</td>
                <td>@course.Credits</td>
                <td>@course.Instructor.Name</td>
                <td><small>@course.Schedule</small></td>
                <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
            </tr>
        }
    </tbody>
</table>

@if (filteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria. Try broadening your search.</div>
}

@code {
    [SupplyParameterFromQuery(Name = "department")]
    public int? DepartmentFromQuery { get; set; }

    private List<Department> departments = new();
    private List<Course> filteredCourses = new();
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        selectedDepartmentId = DepartmentFromQuery ?? 0;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        filteredCourses = CatalogService.SearchCourses(
            searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }

    private void ClearFilters()
    {
        searchTerm = string.Empty;
        selectedDepartmentId = 0;
        ApplyFilters();
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">
        <h4>Course Not Found</h4>
        <p>The requested course could not be found. <a href="courses">Browse all courses</a>.</p>
    </div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="courses?department=@course.DepartmentId">@course.Department.Name</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-md-8">
            <h1>@course.Code — @course.Title</h1>
            <p class="lead">@course.Description</p>

            <h4 class="mt-4">Course Details</h4>
            <table class="table">
                <tbody>
                    <tr><th style="width:200px">Credits</th><td>@course.Credits</td></tr>
                    <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                    <tr><th>Location</th><td>@course.Location</td></tr>
                    <tr><th>Department</th><td>@course.Department.Name</td></tr>
                    <tr>
                        <th>Enrollment</th>
                        <td>
                            @course.CurrentEnrollment / @course.MaxEnrollment
                            @if (course.CurrentEnrollment >= course.MaxEnrollment)
                            {
                                <span class="badge bg-danger ms-2">Full</span>
                            }
                            else
                            {
                                <span class="badge bg-success ms-2">@(course.MaxEnrollment - course.CurrentEnrollment) seats available</span>
                            }
                        </td>
                    </tr>
                </tbody>
            </table>

            <a href="enroll?course=@course.Id" class="btn btn-primary">Request Enrollment</a>
            <a href="courses" class="btn btn-outline-secondary ms-2">Back to Courses</a>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Instructor.Name</h6>
                    <p class="mb-1"><small class="text-muted">@course.Instructor.Title</small></p>
                    <p class="card-text">@course.Instructor.Bio</p>
                    <p class="mb-0"><strong>Email:</strong> <a href="mailto:@course.Instructor.Email">@course.Instructor.Email</a></p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course. You will receive a confirmation from the registrar's office.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@request.StudentName</strong>. Your enrollment request for
            <strong>@(selectedCourse?.Code) — @(selectedCourse?.Title)</strong> has been received.</p>
        <p>The registrar's office will contact you at your university email.</p>
        <a href="/" class="btn btn-outline-primary">Return to Home</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="request" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="request.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="request.StudentId"
                               placeholder="e.g. S12345678" required />
                </div>

                <div class="mb-3">
                    <label for="courseSelect" class="form-label">Course</label>
                    <InputSelect id="courseSelect" class="form-select" @bind-Value="request.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                </div>

                @if (!string.IsNullOrEmpty(validationMessage))
                {
                    <div class="alert alert-danger">@validationMessage</div>
                }

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery(Name = "course")]
    public int? CourseFromQuery { get; set; }

    [SupplyParameterFromForm]
    private EnrollmentRequest request { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;
    private string? validationMessage;
    private Course? selectedCourse;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseFromQuery.HasValue && request.CourseId == 0)
        {
            request.CourseId = CourseFromQuery.Value;
        }
    }

    private void HandleSubmit()
    {
        validationMessage = null;

        if (string.IsNullOrWhiteSpace(request.StudentName))
        {
            validationMessage = "Please enter your full name.";
            return;
        }
        if (string.IsNullOrWhiteSpace(request.StudentId))
        {
            validationMessage = "Please enter your student ID.";
            return;
        }
        if (request.CourseId <= 0)
        {
            validationMessage = "Please select a course.";
            return;
        }

        selectedCourse = CatalogService.GetCourse(request.CourseId);
        if (selectedCourse is null)
        {
            validationMessage = "The selected course was not found.";
            return;
        }

        CatalogService.SubmitEnrollmentRequest(request);
        submitted = true;
    }
}

